			button.MouseButton1Click:Connect(function()
				selectedId = suspect.id
				for _, sibling in ipairs(list:GetChildren()) do
					if sibling:IsA("TextButton") then
						sibling.BackgroundColor3 = UIKit.Palette.PanelBlue
					end
