        content = [====[-- ReplicatedStorage/Modules/Util/Signal.lua
-- Minimal pub-sub helper for internal Controller/Service state changes that don't need
-- to cross the client/server boundary (i.e. don't need a RemoteEvent). Not required by
-- the current Controllers, but available so future UI screens can drive state without
-- per-frame polling, per ROBLOX_UI_SKILL.md §5.

local Signal = {}
Signal.__index = Signal

function Signal.new()
	return setmetatable({ _handlers = {} }, Signal)
end

function Signal:Connect(fn)
	local handlers = self._handlers
	table.insert(handlers, fn)

	local connection = {}
	function connection.Disconnect()
		local index = table.find(handlers, fn)
		if index then
			table.remove(handlers, index)
		end
	end
	return connection
end

function Signal:Fire(...)
	for _, fn in ipairs(self._handlers) do
		task.spawn(fn, ...)
	end
end

return Signal
]====]
    },
}

local function getOrCreatePath(pathStr, className)
	local parts = string.split(pathStr, ".")
	local current = game
	
	-- The first part is always "game" (which is implicit, but parts[1] is "game")
	-- We start from index 2
	for i = 2, #parts - 1 do
		local name = parts[i]
		local child = current:FindFirstChild(name)
		if not child then
			-- If it doesn't exist, create a Folder
			child = Instance.new("Folder")
			child.Name = name
			child.Parent = current
		end
		current = child
	end
	
	local targetName = parts[#parts]
	local target = current:FindFirstChild(targetName)
	if not target then
		target = Instance.new(className)
		target.Name = targetName
		target.Parent = current
	elseif target.ClassName ~= className then
		-- If it exists but class doesn't match, destroy and recreate
		target:Destroy()
		target = Instance.new(className)
		target.Name = targetName
		target.Parent = current
	end
	
	return target
end

local created = 0
local updated = 0
for _, file in ipairs(files) do
	local target = getOrCreatePath(file.path, file.className)
	if target.Source ~= file.content then
		target.Source = file.content
		updated = updated + 1
	else
		created = created + 1 -- already matches
	end
end

-- Also clean up the old EntityAIService under Systems if it exists
local oldAI = game.ServerScriptService:FindFirstChild("GameServer")
if oldAI then
	oldAI = oldAI:FindFirstChild("Systems")
	if oldAI then
		local ai = oldAI:FindFirstChild("EntityAIService")
		if ai then
			ai:Destroy()
			print("Cleaned up old Systems.EntityAIService")
		end
	end
end

return "Sync complete. Created/Verified: " .. created .. ", Updated: " .. updated
